INSERT INTO nomenclatures.nice_class(code, heading, alpha_list) VALUES (16,'Хартия и картон; печатни произведения; материали за подвързване на книги; фотографии; канцеларски принадлежности и канцеларско оборудване, с изключение на мебели; канцеларски лепила и лепила за домакински цели; материали за рисуване и чертане; четки за рисуване; учебни материали; пластмасови листа, фолио и торби за опаковане и пакетиране; печатарски букви, клишета.', 'абсорбиращи листове от хартия или пластмаса за опаковане на хранителни продукти; автоматични писалки; адресни печати [щемпели]; адресни табели за машини за отпечатване на адреси; азбучници; акварели; акварели [картини]; албуми; албуми за залепване на изрезки; алманаси; анимиран целулоид; апарати за монтиране на фотографии; апарати за скици; аритметични таблици; архитектурни макети; атласи; афиши, плакати от хартия или картон; баджове с имена [офис консумативи]; банери от хартия; банкноти; баркод ленти; бележници [канцеларски принадлежности]; биговащи машини [офис принадлежности]; билети; биологически мостри за микроскоп [учебен материал]; бланки, печатни; брокат за канцеларски цели; брошури; букви [печатарски]; бърсалки за писалки; бюлетини с новини; ваденки; валяци за домашно боядисване; валяци за пишещи машини; ванички и палитри за бои; ваучери; вестници; вискозни [целулозни] листове за опаковане; влагоконтролиращи листове от хартия или пластмаса за опаковане на хранителни продукти; восък за моделиране, не за зъболекарски цели; восък за печати; восъчна хартия; въглени моливи; галванични отпечатъци; главни счетоводни книги; глина за моделиране; глутен [лепило] за канцеларски или домакински цели; гравюри; гравюрни плочи; графити за моливи; гребени за декориране с рисунки, имитиращи мрамор; гумени предпазители за пръсти за употреба в офиси; гуми за триене; гъби за почистване на дъски за писане; диаграми; диапозитиви [канцеларски принадлежности]; документни папки [канцеларски принадлежности]; дръжки за графити за моливи; дръжки з