INSERT INTO nomenclatures.nice_class(code, heading, alpha_list) VALUES (31,'Сурови и необработени селскостопански, градинарски и горски продукти и аквакултури; сурови и необработени зърна и семена за посев; пресни плодове и зеленчуци, пресни билки; живи растения и цветя; луковици, разсади и семена за засаждане; живи животни; храни и напитки за животни; малц.', 'алое вера, растения; аншоа, хамсия, жива; аранжирани пресни плодове; ароматизирани котешки тоалетни; артишок, пресен; бадеми [ядки]; бобови култури, пресни; борови шишарки; брашно за храна на животни; брашно от ленено семе за консумация от животни; брезови метлички за сауна; булгур за домашни птици; венци от естествени цветя; водни животни с черупки [раци, миди, скариди], живи; водорасли, необработени за консумация от хора или животни; градински подправки, пресни; грах, пресен; грозде, прясно; гъбен мицел за посяване; гъби, пресни; дестилационен остатък след получаване на алкохолни напитки; джибри; джинджифил, пресен; домашни птици, живи; дървени стърготини за спални постелки за животни; дървени стърготини за производство на дървесен пулп; дървета; еднозърнест лимец, необработен; елда, необработена; ечемик*; живи животни; животни за менажерия; жито; замразена суха риболовна стръв; захарна тръстика; зеленчуци, пресни; зоб; зърно [житни продукти]; зърно за храна на животни; какао на зърна, сурово; канабис, необработен; канабис, растение; картофи, пресни; каша за угояване на добитък; кестени, сурови; киноа, необработена; кои (брокатен шаран), жив; кокосови орехи; коледни елхи*; конопени семена, необработени; копра; коприва; копринени буби; корени от цикория; костно брашно за храна на птици; котешка трева; краставици, пресни; креда за животински фураж; кучешки бисквити; кълнове за ботанически цели; кюспе; кюспе за храна на добитък; кюспе от рапица за храна на добитък; лангусти, живи; ленено брашно [фураж]; ленено семе за консумация от животни; лешници, пресни; леща, прясна; лимони, пресни; лози; лук, пресен; луко