INSERT INTO nomenclatures.nice_class(code, heading, alpha_list) VALUES (32,'Бира; безалкохолни напитки; минерални и газирани води; плодови напитки и плодови сокове; сиропи и други суровини за приготвяне на безалкохолни напитки.', 'аперитиви, безалкохолни; безалкохолна бира; безалкохолни есенции за приготвяне на напитки; безалкохолни коктейли на основата на бира; безалкохолни медени напитки; безалкохолни напитки; безалкохолни напитки от сушени плодове; безалкохолни напитки с аромат на кафе; безалкохолни напитки с вкус на чай; безалкохолни напитки с плодов оцет; безалкохолни плодови екстракти; безалкохолни плодови напитки; бира; бирена мъст; бирени коктейли; води [напитки]; газирана вода; газирана минерална вода; гроздов ейл; гроздова мъст, неферментирала; джинджифилова бира [английска бира]; доматен сок [напитка]; екстракт от хмел за приготвяне на бира; енергийни напитки; ечемична бира; замразен хмел за варене на бира; зеленчукови сокове [напитки]; изотонични напитки; изсушен хмел за варене на бира; квас; коктейли, безалкохолни; лимонади; литиева вода; малцова бира; малцова каша; минерална вода [напитка]; мъст; напитки на основата на ориз, с изключение на заместители на мляко; напитки на основата на соя, различни от заместители на мляко; напитки от алое вера, безалкохолни; напитки от разбити плодове или зеленчуци (смути); оршау [напитка от бадеми]; плодови нектари, безалкохолни; плодови сокове; прахове за пенливи напитки; прахове, използвани за приготвяне на безалкохолни напитки; сайдер, безалкохолна напитка; сарсапарила [безалкохолна напитка] [тонизираща напитка от американска лоза]; сиропи за лимонади; сиропи за напитки; сода [газирана вода]; спортни напитки, обогатени с протеини; суроватъчни напитки; суровини за приготвяне на безалкохолни напитки; суровини за приготвяне на газирана вода; сухи смеси на базата на нишесте за приготвяне на напитки; таблетки за пенливи напитки; трапезни води; хмел на пелети за варене на бира; шанди [бира смесена с лимонада]; шербети [н