INSERT INTO nomenclatures.nice_class(code, heading, alpha_list) VALUES (33,'Алкохолни напитки, с изключение на бира; алкохолни суровини за приготвяне на напитки', 'алкохолни газирани напитки; алкохолни екстракти; алкохолни есенции; алкохолни напитки от захарна тръстика; алкохолни напитки, с изключение на бира; алкохолни напитки, съдържащи плодове; анизет [ликьор]; анис [ликьор]; аперитиви*; арак; ароматизирани варени алкохолни малцови напитки, с изключение на бири; бренди; вино; вишновка; водка; горчивки [ликьори]; дестилатни напитки; дестилирани алкохолни напитки на зърнена основа; джин; дижестиви [ликьори и спиртни напитки]; коктейли*; крушово вино; кюрасо [ликьор]; ликьори; медовина; ментов ликьор; макколи [корейско традиционно оризово вино]; напитки на основата на вино; оризов алкохол; оризово вино; пикет; плодови екстракти, алкохолни; предварително смесени алкохолни напитки, с изключение на тези на базата на бира; ром; сайдер; саке; сожу [ корейски дестилирани напитки ]; спиртни напитки; уиски;');
INSERT INTO nomenclatures.nice_class(code, heading, alpha_list) VALUES (34,'Тютюн и заместители на тютюн; цигари и пури; електронни цигари и изпарители за пушачи (принадлежности); принадлежности за пушачи; кибрит.', 'абсорбираща хартия за лули; бурканчета за тютюн; джобни машинки за свиване на цигари; електронни цигари; енфие; есенции, различни от етерични масла за eлектронни цигари; есенции, различни от етерични масла за тютюн; запалки за пушачи; изпарители (принадлежности) за пушачи; кесии за тютюн; кибритени кутии; кибрити; кремъци; кутии за енфие; кутии за пури; кутии за пури с овлажнител; кюрети за почистване на лули; лули за тютюн; мундщуци за цигарета; наргилета; ножчета за пури; пепелници; плювалници за тютюн; поставки за кибрити; поставки за лули; пурети; пури; резервоарчета за газ за запалки; табакери; течни разтвори за използване в електронни цигари; треви за пушене*; тютюн; тютюн за дъвчене; Устройства за нагряване на тютюн с цел инхалиране; филтри за цигари; филтри на цигари; филтри от жълт кехлибар за цигари и цигарети; фитили за запалки; хартия за цигари; цигарена хартия на книжки; цигарета; цигарета за пури; цигари*; цигари със заместители на тютюн, не за медицински цели;');
INSERT INTO nomenclatures.nice_class(code, heading, alpha_list) VALUES (35,'Реклама; управление и организиране на търговски сделки, търговска администрация; административна дейност', 'абониране за вестници за трети лица; абониране за телекомуникационни услуги за трети лица; абониране за услуги за електронно събиране на пътни такси [ETC] за други; административна помощ в отговор на покани за участие в търгове; административни услуги за медицински направления; административни услуги, свързани с преместване на предприятия; административно обработване на поръчки на клиенти; административно управление на компании от подизпълнител ; административно управление на програми за лоялни клиенти ; административно управление на програми за лоялни клиенти на авиокомпании; административно управление на хотели; актуализиране и поддържане на данни в компютърна база данни; актуализиране и поддържане на информация в регистри; актуализиране на рекламни материали; анализ на себестойността; бизнес консултации във връзка с дигитална трансформация; бизнес мениджмънт на спортисти; бизнес одити; бизнес оценка на търговска ефективност; бизнес посреднически услуги за свързване на потенциални инвеститори с предприемачи, нуждаещи се от финансиране; бизнес посреднически услуги за свързване на различни специалисти с клиенти; бизнес управление за доставчици на услуги на свободна практика; бизнес управление на програми за възстановяване на средства за трети лица; временно бизнес управление; връзки с обществеността; изготвяне на ведомости; изготвяне на потребителски профил за търговски или маркетингови цели; изготвяне на проучвания за рентабилност на бизнеса; изготвяне на статистически данни; издаване на фактури; изследване на пазара; изследвания с търговска цел; икономическо прогнозиране; интернет индексиране за търговски или рекламни цели; компютърно управление на медицински досиета и файлове; консултантски услуги в областта на човешките ресурси; консултантски услуги за търговско управление; консултации в областта на организирането на търговията; консултации в областта на търговското управление; консултации относно комуникационна стратегия за връзки с обществеността; консултации относно комуникационна стратегия за реклама; корпоративни комуникационни услуги; маркетинг ; маркетинг в рамките на издаване на софтуер; маркетинг чрез инфлуенсъри; маркетинг чрез позициониране на продукти във виртуални среди за трети лица; машинописни услуги; набиране на кадри; набиране на спонсори; насърчаване на продажбите за трети лица; онлайн реклама в компютърна мрежа; онлайн услуги за търговия на дребно с виртуални дрехи с възможност за изтегляне; онлайн услуги за търговия на дребно с мелодии за мобилни телефони, с възможност за изтегляне; онлайн услуги за търговия на дребно с предварително записани музика и филми, с възможност за изтегляне; онлайн услуги за търговия на дребно с цифрова музика, с възможност за изтегляне от интернет; оптимизиране на търсещи системи, с цел увеличаване на продажбите; оптимизиране на уеб сайт-трафик; организиране и провеждане на търговски събития; организиране на изложби с търговска или рекламна цел; организиране на модни ревюта с промоционална цел; организиране на търгове; организиране на търговски панаири; осигуряване на онлайн пазара за покупко-продажба на стоки и услуги; осигуряване на онлайн пазара за покупко-продажба на цифрови файлове с изображения, с възможност за изтегляне, удостоверени с незаменими токени [NFT]; отдаване под наем на автомати за продажба; отдаване под наем на канцеларски машини и апарати*; отдаване под наем на касови апарати; отдаване под наем на офис оборудване в помещения за съвместна работа; отдаване под наем на рекламни билбордове; отдаване под наем на рекламни съоръжения; отдаване под наем на рекламно време във всички средства за комуникация; отдаване под наем на рекламно пространство и време; отдаване под наем на търговски щандове; отдаване под наем на фотокопирни машини; пей пър клик реклама; писане на сценарии за рекламни цели; подизпълнителски услуги (търговско подпомагане); подпомагане на търговското управление; подреждане на витрини; помощ при управление на търговски или промишлени предприятия; попълване на данъчни декларации; преглед на печата; предоставяне на бизнес информация чрез уебсайт; предоставяне на информация от телефонния указател; предоставяне на класации от потребителите за търговски или рекламни цели; предоставяне на отзиви от страна на потребителите за търговски или рекламни цели; предоставяне на потребителски оценки за търговски или рекламни цели; предоставяне на търговска и фирмена информация за контакт; предоставяне на търговска информация; предоставяне на търговска информация и консултации за потребители при избора на продукти и услуги; представяне на стоки; представяне на стоки на дребно с цел продажба чрез комуникационни средства; приемане на телефонни съобщения за отсъстващи абонати; производство на програми за телешопинг; производство на рекламни филми; проучване на общественото мнение; проучване на пазара; проучване с търговска цел; професионални консултации в областта на търговията; психологическо тестване за подбор на кадри; публикуване на рекламни текстове; радиорекламиране; разпространение на мостри; разпространение на рекламни материали; разпространение на рекламни материали по пощата [листовки, проспекти, брошури, мостри]; разработване на маркетингови концепции; Разработване на пазарни проучвания; разработване на рекламни материали; разработване на стратегии за бизнес организация, свързани с корпоративната социална отговорност; регистриране на писмени съобщения и данни; реклама; рекламиране на открито; рекламиране на стоки и услуги чрез спонсорство на спортни събития; рекламиране на стоки чрез инфлуенсъри; рекламиране чрез афиши; рекламиране чрез пощенски поръчки; рекламиране чрез телевизията; рекламни услуги за създаването на идентичност на марка за други; секретарски услуги; систематизиране на информация в компютърни бази данни; снабдяване за сметка на трети лица [закупуване на стоки или услуги за други предприятия]; стенографски услуги; счетоводни услуги; събиране на информация в компютърни бази данни; създаване на рекламни текстове; съставяне на автобиографии за трети лица; съставяне на извлечения от сметки; съставяне на индекси на информация за търговски или рекламни цели; текстообработка; телемаркетингови услуги; транскрибиране на съобщения [административна дейност]; търговия на дребно с пекарски тестени изделия; търговия на дребно с произведения на изкуството, предоставени от художествени галерии; търговия на дребно с фармацевтични, ветеринарни, санитарни и медицински препарати; търговия на едро с фармацевтични, ветеринарни и санитарни препарати и медицински консумативи; търговски оценки; търговски посреднически услуги; търговски справки; търговско управление на лицензиране на стоки и услуги за трети лица; търсене в компютърни бази данни за трети лица; търсене на бизнес партньорство; търсене на потенциални продажби за трети лица; управление на бизнес проекти; управление на компютърни файлове; управление на сделки в областта на изкуството; уреждане на бизнес договори за трети лица; услуги за маркетингови изследвания; услуги за медийни връзки; услуги за напомняне за уговорени срещи [административна дейност]; услуги за обработка на данни [административна дейност]; услуги за онлайн поръчки в областта на храна за вкъщи и доставка от ресторант; услуги за подаване на данъчни декларации; услуги за посрещане на посетители [административна дейност]; услуги за проучване на конкуренцията; услуги за регистър с желани подаръци; услуги за създаване на потенциални клиенти; услуги за търговия на дребно, свързани с файлове с цифрови изображения за изтегляне, удостоверени с незаменими токени [NFTs]; услуги за търговско лобиране; услуги за уреждане на срещи [административна дейност]; услуги за художествено оформление за рекламни цели; услуги на агенции за внос и износ; услуги на агенции за търговска информация; услуги на кол центрове; услуги на манекени, свързани с рекламиране и представяне на стоки; услуги на рекламни агенции; услуги на трудови борси; услуги, свързани с водене на преговори и сключване на търговски сделки за сметка на трети лица; услуги, свързани със сравняване на цени; финансови одити; фотокопирни услуги; целеви маркетинг;');
INSERT INTO nomenclatures.nice_class(code, heading, alpha_list) VALUES (36,'Финансови, парични и банкови услуги; застрахователни услуги; услуги, свързани с недвижими имоти.', 'банково дело; бизнес посредничество; борсови котировки; борсово посредничество; брокерски услуги свързани с въглеродни кредити; брокерски услуги*; брокерски услуги за автомобили; взаимни фондове; данъчни оценки; депозити на ценни книжа; електронен трансфер на капитали; електронно прехвърляне на криптовалута; електронно прехвърляне на средства чрез блокчейн технология; застраховане; застраховане срещу пожар; застрахователни консултации; застрахователно посредничество; застраховка-живот; застраховки срещу злополуки; здравни застраховки; изготвяне на оферти за целите на оценка на разходите; издаване на ваучери за подарък; издаване на кредитни карти; издаване на предплатени ваучери; издаване на предплатени подаръчни карти; издаване на пътнически чекове; инвестиране на капитали; консултантски услуги по дългове; лизингови сделки при покупки на изплащане; ликвидация на предприятия, финансови сделки; морски застраховки; обмяна на валута; обработване на плащания с дебитни карти; обработване на плащания с кредитни карти; обслужване на депозити в сейфове; обслужване на пенсионни плащания; онлайн банкиране; онлайн банкови услуги, предоставяни във виртуална среда; организиране на кампании за набиране на средства за благотворителни цели; организиране на събития за набиране на средства; осигуряване на финансиране за строителни проекти; отдаване под наем на апартаменти; отдаване под наем на недвижимо имущество; отдаване под наем на офиси [сделки с недвижимо имущество]; отдаване под наем на офиси за съвместна работа; отдаване под наем на пасища; отдаване под наем на ферми; отпускане на заеми при изплащане на части; отпускане на заеми срещу залог; отпускане на заеми срещу ипотека; отпускане на кредити; оценяване на антики; оценяване на бижута; оценяване на монети; оценяване на недвижимо имущество; оценяване на 