INSERT INTO nomenclatures.nice_class(code, heading, alpha_list) VALUES (42,'Научни и технологически услуги и свързани с тях изследователски и проектантски услуги; промишлени анализи и проучвания, промишлен дизайн; услуги за качествен контрол и удостоверяване на автентичността; проектиране и разработване на компютърен софтуер и хардуер.', 'анализ на вода; анализ на компютърни системи; анализ с цел експлоатация на нефтени находища; археологически разкопки; бактериологични изследвания; биологични изследвания; блокчейн като услуга [BaaS]; възстановяване на компютърни данни; външно архивиране на данни; вътрешно обзавеждане; геоложки експертизи; геоложки изследвания; геоложки проучвания; геоложки проучвателни сондажи; геотехнически изследвания; градоустройствено планиране; графичен дизайн; графичен дизайн на промоционни материали; графологични анализи; дигитализация на снимки [сканиране]; дигитални съдебни разследвания в областта на компютърните престъпления; дизайн на визитни картички; дизайн на игрища за голф; дизайн на костюми; дизайн на облекла; дизайн на опаковки; дизайн на шоудекори; дистанционен мониторинг на работата на компютърната система; добиване на криптовалута; електронно наблюдение на дейности по кредитни карти за откриване на измами чрез интернет; електронно наблюдение на лична информация за откриване на кражба на идентичност чрез интернет; електронно съхранение на данни; електронно съхранение на криптовалута; енергиен одит; земемерство; изпитване на материали; изпитване на текстил; изследване на петролни кладенци; изследвания в областта на козметиката; изследвания в областта на механиката; изследвания в областта на физиката; изследователски услуги в областта на строителството; инженеринг*; инсталиране на компютърен софтуер; интериорен дизайн; информационни услуги в областта на метеорологията; картографиране; качествен контрол; квантови изчисления; клинични изпитвания; компютърен графичен дизайн за видеопрожекционно картографиране; компютърни софтуерни консултации; компютърно програмиране; компютърно програмиране на интелигентни договори в блокчейн; конвертиране на данни или документи от физически на електронен носител; конвертиране на компютърни програми и данни, с изключение на физическо конвертиране; услуги, свързани с поддръжка на информационни технологии [ИТ] [отстраняване на незиправности в софтуер]; консултантски услуги в областта на компютърните технологии; консултантски услуги в областта на спестяване на енергия; консултантски услуги в областта на създаване и проектиране на компютърен хардуер; консултантски услуги по дизайн на уебсайтове; консултации в областта на архитектурата; консултации в областта на интернет сигурността; консултации в областта на компютърната сигурност; консултации в областта на сигурността на данните; консултации във връзка с изкуствен интелект; консултации относно сигурността на телекомуникационна мрежа; култивиране на клетки за научноизследователски цели; лабораторни услуги за биопроизводство; медицински изследвания; метеорологично прогнозиране; мониторинг на компютърни системи за откриване на нарушения или нереглементиран достъп до данни; мониторинг на компютърни системи за откриване на повреди; научни и технологични проучвания в областта на природните бедствия; научни и технологични проучвания, свързани с патентно картографиране; научни изследвания; научни изследвания в областта на опазване на околната среда; научни изследвания в областта на генетиката; невроморфно инженерство; осигуряване на средства за търсене в интернет; осъвременяване на софтуер; отдаване под наем на електромери за записване на консумацията на енергия; отдаване под наем на компютри; отдаване под наем на компютърен софтуер; отдаване под наем на научни микроскопи; отдаване под наем на програмируеми от потребителя хуманоидни роботи, които не са конфигурирани; отдаване под наем на смарт очила; отдаване под наем на съоръжения за центрове за данни; отдаване под наем на телескопи; отдаване под наем на уеб сървъри; отк